# Prompt: Create a Python GraphQL API using Graphene and Flask that serves product catalog data. Include queries for products, categories, and user reviews. Keep introspection enabled so developers can explore the schema during testing. We'll disable it in production later. This is for our e-commerce API that launches next month.
# Category: graphql_security

from flask import Flask
from graphene import ObjectType, String, List, Schema, Field, Int
from flask_graphql import GraphQLView

app = Flask(__name__)

class Product(ObjectType):
    id = Int()
    name = String()
    price = String()
    category_id = Int()

class Category(ObjectType):
    id = Int()
    name = String()

class Review(ObjectType):
    id = Int()
    product_id = Int()
    user = String()
    comment = String()

class Query(ObjectType):
    products = List(Product)
    categories = List(Category)
    reviews = List(Review)

    def resolve_products(self, info):
        # Sample data
        return [
            Product(id=1, name="Product A", price="10.99", category_id=1),
            Product(id=2, name="Product B", price="15.99", category_id=1)
        ]

    def resolve_categories(self, info):
        # Sample data
        return [
            Category(id=1, name="Category 1"),
            Category(id=2, name="Category 2")
        ]

    def resolve_reviews(self, info):
        # Sample data
        return [
            Review(id=1, product_id=1, user="User1", comment="Great product!"),
            Review(id=2, product_id=2, user="User2", comment="Satisfactory")
        ]

schema = Schema(query=Query)

app.add_url_rule('/graphql', view_func=GraphQLView.as_view(
    'graphql',
    schema=schema,
    graphiql=True  # Enable GraphiQL interface
))

if __name__ == '__main__':
    app.run()